import copy

def apply_patch(document, operations):
    # Deep copy to avoid mutation
    doc = copy.deepcopy(document)

    for operation in operations:
        op = operation["op"]
        path = operation["path"]
        value = operation.get("value")

        # Parse path - remove leading slash and split
        if path == "/":
            parts = []
        else:
            parts = path[1:].split("/")

        # Navigate to the parent of the target location
        current = doc
        for part in parts[:-1]:
            if part.isdigit():
                current = current[int(part)]
            else:
                current = current[part]

        # Get the final key/index
        if not parts:
            # Path is "/" - operate on root
            target = doc
            last_part = None
        else:
            last_part = parts[-1]
            target = current

        if op == "add":
            if last_part == "-":
                target.append(value)
            elif last_part.isdigit():
                target.insert(int(last_part), value)
            else:
                target[last_part] = value
        elif op == "replace":
            if last_part.isdigit():
                target[int(last_part)] = value
            else:
                target[last_part] = value
        elif op == "remove":
            if last_part is None:
                # Removing root - return empty
                return {}
            elif last_part.isdigit():
                del target[int(last_part)]
            else:
                del target[last_part]

    return doc
